using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// Sub-painel "Galeria" do Menu Principal (Tarefa #39) — mostra ilustrações/artes
/// conceptuais desbloqueadas pelo jogador.
///
/// Cada entrada é um <see cref="GaleriaEntry"/>: imagem, título e condição de
/// desbloqueio (variável bool em GameVariables; vazio = sempre visível).
/// Entradas bloqueadas aparecem como silhueta (sprite <see cref="lockedSprite"/>).
///
/// Navegação:
/// - Grelha de miniaturas com botões — ao seleccionar uma, abre o <see cref="viewerPanel"/>
///   com a imagem em grande + título.
/// - "Fechar viewer": volta à grelha.
/// - "Voltar" (ou B/Escape): fecha o painel e dispara <see cref="Closed"/>.
///
/// Montagem no Editor:
/// - "root": GameObject raiz (escondido por defeito).
/// - "thumbnailContainer": Transform pai dos botões de miniatura (usar Grid Layout Group).
/// - "thumbnailPrefab": prefab com Image + Button + TMP_Text (título abaixo).
/// - "viewerPanel"/"viewerImage"/"viewerTitle"/"closeViewerButton": painel de visualização.
/// - "backButton"/"firstSelectable": controlo de fecho e primeiro foco.
/// - "lockedSprite": sprite mostrado quando entrada está bloqueada.
/// - "entries": lista configurada no Inspector.
/// </summary>
public class GaleriaUI : MonoBehaviour, ICancelHandler
{
    [Header("Framework")]
    [SerializeField] private GameObject root;
    [SerializeField] private Selectable firstSelectable;
    [SerializeField] private Button backButton;

    [Header("Grelha de Miniaturas")]
    [SerializeField] private Transform thumbnailContainer;
    [SerializeField] private GameObject thumbnailPrefab;

    [Header("Sprite de Bloqueado")]
    [Tooltip("Sprite mostrado no lugar de entradas ainda não desbloqueadas.")]
    [SerializeField] private Sprite lockedSprite;

    [Header("Viewer (imagem em grande)")]
    [SerializeField] private GameObject viewerPanel;
    [SerializeField] private Image viewerImage;
    [SerializeField] private TMP_Text viewerTitle;
    [SerializeField] private Button closeViewerButton;

    [Header("Entradas da Galeria")]
    public List<GaleriaEntry> entries = new List<GaleriaEntry>();

    /// <summary>Disparado ao fechar o painel (botão Voltar ou B/Escape).</summary>
    public event System.Action Closed;

    public GameObject Root => root != null ? root : gameObject;

    private readonly List<GameObject> _spawnedThumbs = new List<GameObject>();

    private void Awake()
    {
        if (backButton != null) backButton.onClick.AddListener(Close);
        if (closeViewerButton != null) closeViewerButton.onClick.AddListener(CloseViewer);
        if (root != null) root.SetActive(false);
        if (viewerPanel != null) viewerPanel.SetActive(false);
    }

    // ---------------- Abrir / Fechar ----------------

    public void Open()
    {
        if (root != null) root.SetActive(true);
        BuildGrid();
        CloseViewer();
        SelectFirst();
    }

    public void Close()
    {
        CloseViewer();
        if (root != null) root.SetActive(false);
        Closed?.Invoke();
    }

    public void OnCancel(BaseEventData eventData)
    {
        if (viewerPanel != null && viewerPanel.activeSelf)
            CloseViewer();
        else
            Close();
    }

    // ---------------- Grelha ----------------

    private void BuildGrid()
    {
        // Limpa miniaturas anteriores.
        foreach (var go in _spawnedThumbs)
            if (go != null) Destroy(go);
        _spawnedThumbs.Clear();

        if (thumbnailContainer == null || thumbnailPrefab == null) return;

        var vars = GameVariables.Instance;

        for (int i = 0; i < entries.Count; i++)
        {
            var entry = entries[i];
            if (entry == null) continue;

            bool unlocked = string.IsNullOrEmpty(entry.unlockVariable)
                || (vars != null && vars.GetBool(entry.unlockVariable));

            var go = Instantiate(thumbnailPrefab, thumbnailContainer);
            _spawnedThumbs.Add(go);

            // Imagem da miniatura.
            var img = go.GetComponentInChildren<Image>();
            if (img != null)
                img.sprite = unlocked ? entry.artwork : lockedSprite;

            // Título.
            var label = go.GetComponentInChildren<TMP_Text>();
            if (label != null)
                label.text = unlocked ? entry.title : "???";

            // Botão — só funciona se desbloqueado.
            var btn = go.GetComponentInChildren<Button>();
            if (btn != null)
            {
                btn.interactable = unlocked;
                if (unlocked)
                {
                    var captured = entry;
                    btn.onClick.AddListener(() => OpenViewer(captured));
                }
            }
        }
    }

    // ---------------- Viewer ----------------

    private void OpenViewer(GaleriaEntry entry)
    {
        if (viewerPanel == null) return;

        if (viewerImage != null) viewerImage.sprite = entry.artwork;
        if (viewerTitle != null) viewerTitle.text = entry.title;

        viewerPanel.SetActive(true);

        if (EventSystem.current != null && closeViewerButton != null)
            EventSystem.current.SetSelectedGameObject(closeViewerButton.gameObject);
    }

    private void CloseViewer()
    {
        if (viewerPanel != null) viewerPanel.SetActive(false);
        SelectFirst();
    }

    // ---------------- Utilitários ----------------

    private void SelectFirst()
    {
        if (EventSystem.current != null && firstSelectable != null)
            EventSystem.current.SetSelectedGameObject(firstSelectable.gameObject);
    }
}

/// <summary>
/// Uma entrada na galeria: arte conceptual, título e condição de desbloqueio.
/// </summary>
[System.Serializable]
public class GaleriaEntry
{
    [Tooltip("Sprite da ilustração/arte conceptual.")]
    public Sprite artwork;

    [Tooltip("Título mostrado abaixo da miniatura e no viewer.")]
    public string title;

    [Tooltip("Variável bool em GameVariables que indica se esta arte está desbloqueada. Vazio = sempre visível.")]
    public string unlockVariable;
}
